FILES = {'core/__init__.py': '', 'core/config.py': '# -*- coding: utf-8 -*-\nfrom pathlib import Path\n\nBASE_DIR = Path(r"C:\\Users\\MSI\\Desktop\\kik_proje")\nPY_DIR = BASE_DIR / ".py"\nSTATE_DIR = BASE_DIR / "production_state"\nREPORT_DIR = BASE_DIR / "raporlar"\n\nEXECUTION_DIR = STATE_DIR / "execution"\nEXECUTION_HISTORY = EXECUTION_DIR / "207_execution_history.jsonl"\nEXECUTION_SNAPSHOT = EXECUTION_DIR / "207_execution_snapshot.json"\nEXECUTION_DASHBOARD = EXECUTION_DIR / "207_execution_dashboard.json"\n\nSCHEDULER_SNAPSHOT = STATE_DIR / "scheduler" / "206_scheduler_snapshot.json"\nSCHEDULER_DASHBOARD = STATE_DIR / "scheduler" / "206_scheduler_dashboard.json"\n\nQUEUE_FILE = STATE_DIR / "job_queue" / "198_job_queue_state.json"\nWORKER_FILE = STATE_DIR / "job_queue" / "198_worker_state.json"\n\nDEFAULT_EXECUTION_MODE = "CONTROLLED"\nMAX_PARALLEL_WORKERS = 3\n', 'core/utils.py': '# -*- coding: utf-8 -*-\nimport json\nfrom pathlib import Path\nfrom datetime import datetime\n\ndef now_stamp():\n    return datetime.now().strftime("%Y%m%d_%H%M%S")\n\ndef now_text():\n    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")\n\ndef ensure_dirs(*dirs):\n    for d in dirs:\n        Path(d).mkdir(parents=True, exist_ok=True)\n\ndef safe_read(path, limit_chars=5000000):\n    path = Path(path)\n    if not path.exists():\n        return ""\n    for enc in ("utf-8", "utf-8-sig", "cp1254", "latin-1"):\n        try:\n            return path.read_text(encoding=enc, errors="ignore")[:limit_chars]\n        except Exception:\n            pass\n    return ""\n\ndef safe_json(path):\n    path = Path(path)\n    if not path.exists():\n        return None\n    try:\n        return json.loads(safe_read(path))\n    except Exception:\n        return None\n\ndef write_json(path, data):\n    path = Path(path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")\n\ndef append_jsonl(path, data):\n    path = Path(path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    with path.open("a", encoding="utf-8") as f:\n        f.write(json.dumps(data, ensure_ascii=False) + "\\n")\n\ndef clamp(value, low=0, high=100):\n    try:\n        value = float(value)\n    except Exception:\n        value = 0\n    return max(low, min(high, value))\n', 'core/loader.py': '# -*- coding: utf-8 -*-\nfrom .config import SCHEDULER_SNAPSHOT, SCHEDULER_DASHBOARD, QUEUE_FILE, WORKER_FILE\nfrom .utils import safe_json\n\nclass ExecutionLoader:\n    def load_scheduler_snapshot(self):\n        return safe_json(SCHEDULER_SNAPSHOT) or {}\n\n    def load_scheduler_dashboard(self):\n        return safe_json(SCHEDULER_DASHBOARD) or {}\n\n    def load_queue(self):\n        return safe_json(QUEUE_FILE) or {}\n\n    def load_workers(self):\n        return safe_json(WORKER_FILE) or {}\n\n    def load_all(self):\n        return {\n            "scheduler_snapshot": self.load_scheduler_snapshot(),\n            "scheduler_dashboard": self.load_scheduler_dashboard(),\n            "queue": self.load_queue(),\n            "workers": self.load_workers(),\n        }\n', 'core/context.py': '# -*- coding: utf-8 -*-\nfrom .utils import now_text\n\nclass ExecutionContextBuilder:\n    def build(self, raw):\n        scheduler_decision = (raw.get("scheduler_snapshot", {}) or {}).get("decision", {})\n        dashboard = raw.get("scheduler_dashboard", {}) or {}\n        queue_jobs = raw.get("queue", {}).get("jobs", [])\n        workers = raw.get("workers", {}).get("workers", [])\n\n        waiting_jobs = [j for j in queue_jobs if j.get("status") == "WAITING"]\n        idle_workers = [w for w in workers if w.get("status") in ("IDLE", "idle")]\n\n        return {\n            "created_at": now_text(),\n            "scheduler_decision": scheduler_decision.get("decision") or dashboard.get("last_decision"),\n            "scheduler_risk": scheduler_decision.get("risk") or dashboard.get("risk"),\n            "recommended_batch_size": scheduler_decision.get("recommended_batch_size") or dashboard.get("recommended_batch_size") or 0,\n            "reason": scheduler_decision.get("reason"),\n            "queue": {\n                "total_jobs": len(queue_jobs),\n                "waiting_jobs": len(waiting_jobs),\n                "selected_jobs": min(len(waiting_jobs), scheduler_decision.get("recommended_batch_size") or dashboard.get("recommended_batch_size") or 0),\n            },\n            "workers": {\n                "total_workers": len(workers),\n                "idle_workers": len(idle_workers),\n                "available_worker_ids": [w.get("worker_id") or w.get("id") or f"worker-{i+1}" for i, w in enumerate(idle_workers)],\n            },\n        }\n', 'core/validator.py': '# -*- coding: utf-8 -*-\nclass ExecutionValidator:\n    def validate(self, context):\n        errors = []\n        warnings = []\n\n        if context.get("scheduler_decision") in (None, ""):\n            errors.append("Scheduler decision bulunamadı.")\n\n        if context.get("scheduler_decision") == "PAUSE_PRODUCTION":\n            errors.append("Scheduler üretimi durdurma kararı vermiş.")\n\n        if context["workers"]["idle_workers"] == 0:\n            errors.append("Idle worker yok.")\n\n        if context["queue"]["waiting_jobs"] == 0:\n            warnings.append("Waiting job yok.")\n\n        if context["queue"]["selected_jobs"] == 0:\n            warnings.append("Seçilecek job sayısı 0.")\n\n        score = 100 - min(60, len(errors) * 20) - min(30, len(warnings) * 5)\n        decision = "EXECUTION CONTEXT READY" if not errors else "EXECUTION CONTEXT BLOCKED"\n\n        return {"score": score, "decision": decision, "errors": errors, "warnings": warnings}\n', 'core/planner.py': '# -*- coding: utf-8 -*-\nclass ExecutionPlanner:\n    def plan(self, context, validation):\n        if validation["errors"]:\n            return {\n                "execution_mode": "PAUSED",\n                "assignments": [],\n                "message": "Execution blocked by validation errors.",\n            }\n\n        selected = context["queue"]["selected_jobs"]\n        workers = context["workers"]["available_worker_ids"]\n\n        assignments = []\n        if workers and selected > 0:\n            for i in range(selected):\n                assignments.append({\n                    "job_slot": i + 1,\n                    "worker_id": workers[i % len(workers)],\n                    "status": "PLANNED",\n                })\n\n        return {\n            "execution_mode": "CONTROLLED",\n            "assignments": assignments,\n            "message": f"{len(assignments)} job slot planned across {len(workers)} idle workers.",\n        }\n', 'core/exporter.py': '# -*- coding: utf-8 -*-\nfrom .config import EXECUTION_DIR, EXECUTION_HISTORY, EXECUTION_SNAPSHOT, EXECUTION_DASHBOARD, REPORT_DIR, STATE_DIR\nfrom .utils import ensure_dirs, now_stamp, write_json, append_jsonl\n\nclass ExecutionExporter:\n    def export(self, payload, name="207_0_execution_sdk"):\n        ensure_dirs(EXECUTION_DIR, REPORT_DIR, STATE_DIR)\n        ts = now_stamp()\n        state = STATE_DIR / f"{name}_state_{ts}.json"\n        report = REPORT_DIR / f"{name}_raporu_{ts}.txt"\n\n        write_json(EXECUTION_SNAPSHOT, payload)\n        write_json(state, payload)\n        append_jsonl(EXECUTION_HISTORY, payload)\n\n        dashboard = {\n            "execution_status": payload.get("validation", {}).get("decision"),\n            "execution_mode": payload.get("plan", {}).get("execution_mode"),\n            "assignment_count": len(payload.get("plan", {}).get("assignments", [])),\n            "risk": payload.get("context", {}).get("scheduler_risk"),\n            "scheduler_decision": payload.get("context", {}).get("scheduler_decision"),\n        }\n        write_json(EXECUTION_DASHBOARD, dashboard)\n\n        lines = [\n            "=" * 80,\n            "207.0 EXECUTION SDK",\n            "=" * 80,\n            "Validation : " + str(payload.get("validation", {}).get("decision")),\n            "Score      : " + str(payload.get("validation", {}).get("score")),\n            "Mode       : " + str(payload.get("plan", {}).get("execution_mode")),\n            "Assignments: " + str(len(payload.get("plan", {}).get("assignments", []))),\n            "",\n            "Message:",\n            str(payload.get("plan", {}).get("message")),\n            "",\n            "Dosyalar:",\n            str(EXECUTION_SNAPSHOT),\n            str(EXECUTION_DASHBOARD),\n            str(state),\n            str(report),\n        ]\n        report.write_text("\\n".join(lines), encoding="utf-8")\n\n        return {"snapshot": str(EXECUTION_SNAPSHOT), "dashboard": str(EXECUTION_DASHBOARD), "state": str(state), "report": str(report)}\n', 'core/sdk.py': '# -*- coding: utf-8 -*-\nfrom .loader import ExecutionLoader\nfrom .context import ExecutionContextBuilder\nfrom .validator import ExecutionValidator\nfrom .planner import ExecutionPlanner\nfrom .exporter import ExecutionExporter\nfrom .utils import now_text\n\nclass ExecutionSDK:\n    def __init__(self, name="207.0 Execution SDK"):\n        self.name = name\n        self.loader = ExecutionLoader()\n        self.context_builder = ExecutionContextBuilder()\n        self.validator = ExecutionValidator()\n        self.planner = ExecutionPlanner()\n        self.exporter = ExecutionExporter()\n\n    def run(self):\n        raw = self.loader.load_all()\n        context = self.context_builder.build(raw)\n        validation = self.validator.validate(context)\n        plan = self.planner.plan(context, validation)\n        payload = {\n            "module": self.name,\n            "created_at": now_text(),\n            "context": context,\n            "validation": validation,\n            "plan": plan,\n        }\n        paths = self.exporter.export(payload)\n        return {"payload": payload, "paths": paths}\n', 'execution_sdk_manager.py': '# -*- coding: utf-8 -*-\nimport argparse\nfrom core.sdk import ExecutionSDK\n\ndef main():\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--test", action="store_true")\n    parser.add_argument("--status", action="store_true")\n    args = parser.parse_args()\n\n    res = ExecutionSDK().run()\n    payload = res["payload"]\n    validation = payload["validation"]\n    plan = payload["plan"]\n\n    print("=" * 80)\n    print("207.0 EXECUTION SDK TAMAMLANDI")\n    print("=" * 80)\n    print("Validation : " + str(validation["decision"]))\n    print("Score      : " + str(validation["score"]) + " / 100")\n    print("Errors     : " + str(len(validation["errors"])))\n    print("Warnings   : " + str(len(validation["warnings"])))\n    print("Mode       : " + str(plan["execution_mode"]))\n    print("Assignments: " + str(len(plan["assignments"])))\n    print("")\n    print("Dosyalar:")\n    print(res["paths"]["snapshot"])\n    print(res["paths"]["dashboard"])\n    print(res["paths"]["report"])\n\nif __name__ == "__main__":\n    main()\n'}
